const content = $input.first().json.content.split('\n')
  .map(line => line.trim())
  .filter(line => line.length > 0);

return {
  json: {
    content: content
  }
};

let file_name_list = [];

const data = $input.all().reduce((acc, item) => {
  const metadata = item.json.metadata;
  const filename = metadata.file_name;

  if (!file_name_list.includes(filename)) {
    acc.push({
      json: {
        file_name: filename,
        file_extension: metadata.file_extension,
        file_modified_time: metadata.modified_time,
        document_id: metadata.document_id
      }
    });
    file_name_list.push(filename);
  }

  return acc;
}, []);

return data;

let inputText = $input.first().json.output;
const splitList = inputText.split('```json');
inputText = splitList[splitList.length - 1];
const updatedText = inputText.replaceAll(/\n\s*/g, '')
  .replace(/```/g, '');

let parsedOutput;
try {
  parsedOutput = JSON.parse(updatedText);
} catch (error) {
  parsedOutput = {
    text: updatedText
  };
}

return {
  json: parsedOutput
};

const inputText = $input.first().json.text;
const inputMD = $input.first().json.markdown;

const output = inputMD && inputMD.trim() !== ''
  ? inputText + '\n```html\n' + inputMD + '\n```'
  : inputText;

return {
  json: {
    output: output
  }
};

const inputText = $input.first().json.output;
const updatedText = inputText.replaceAll(/\n\s*/g, '')
  .replace(/```html|```/g, '');

return {
  json: {
    email_body: updatedText
  }
}

for (const item of $input.all()) {
  const emailArray = item.json.send_to_email;
  item.json.send_to_email = `{${emailArray.join(',')}}`;
}

return $input.all();

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
const sheets = $input.first().json.sheets.map(sheet => {
  return sheet.properties.title;
});

return {
  json: {
    sheet_name: sheets
  }
}

const rows = $input.all().map(row => {
  return Object.entries(row.json)
    .map(([key, value]) => `'${key}': '${value}'`)
    .join(', ');
});

return {
  json: {
    content: `{${rows}}`
  }
};

for (const item of $input.all()) {
  const content = Object.entries(item.json)
    .reduce((acc, [key, value], index) => {
      if (index !== 1) return acc;
      acc[key] = value;
      return acc;
    }, {});
  const meta_data = Object.entries(item.json)
    .reduce((acc, [key, value], index) => {
      if (index === 1) return acc;
      acc[key] = value;
      return acc;
    }, {});
  item.json.content = JSON.stringify(content)
    .replaceAll('"', '')
    .replaceAll('{', '')
    .replaceAll('}', '')
  item.json.meta_data = meta_data
}

return $input.all();

// Loop over input items and add a new field called 'myNewField' to the JSON of each one
for (const item of $input.all()) {
  const name = item.json.name;
  item.json.email_body = item.json.email_body.replaceAll('{{name}}', name);
}

return $input.all();
